  ('a2d0114b-1946-4198-bc42-4a20a17719ee'::uuid, '523c7c07-89bd-4d93-8463-53e92bc35307'::uuid, null, 'product_updated', 'codex_blackmores_clean_approval', '{"id":"523c7c07-89bd-4d93-8463-53e92bc35307","title":"Blackmores Iron Rapi-Melt™","region":"TH","source":"manufacturer_import","status":"pending_review","brand_id":"40e4806a-5049-4668-8d29-ab36a31202dd","category":null,"currency":"THB","platform":"manual","title_en":"Blackmores Iron Rapi-Melt™","title_th":null,"image_url":"https://images.contentstack.io/v3/assets/blt948bd74310fc0ad0/blt5fed7771c97a84ac/68bfbd487f7a0149ebb3ec2e/9300807364963-1.webp","brand_name":"blackmores","created_at":"2026-05-21T13:09:46.196682+00:00","source_url":"https://www.blackmores.com.au/products/iron-rapi-melt","updated_at":"2026-05-21T13:09:46.219718+00:00","admin_notes":null,"description":"Blackmores Iron Rapi-Melt™ supports iron levels and reduces tiredness when dietary intake is inadequate.","product_url":"https://www.blackmores.com.au/products/iron-rapi-melt","label_status":"parsed","price_amount":null,"product_kind":"supplement","description_en":"Blackmores Iron Rapi-Melt™ supports iron levels and reduces tiredness when dietary intake is inadequate.","description_th":null,"normalized_url":"https://www.blackmores.com.au/products/iron-rapi-melt","current_version":1,"fda_verified_at":null,"price_cached_at":null,"source_snapshot":{"dosage":"for use. Read the","locale":"en","parser":"blackmores_structured_ingredients_v2","titleEn":"Blackmores Iron Rapi-Melt™","htmlLength":170172,"validation":{"status":"pass","reasons":[],"summary":"2 matchable canonical facts.","checkedAt":"2026-05-21T13:09:46.218Z","matchableFactCount":2},"description":"Blackmores Iron Rapi-Melt™ supports iron levels and reduces tiredness when dietary intake is inadequate.","descriptionEn":"Blackmores Iron Rapi-Melt™ supports iron levels and reduces tiredness when dietary intake is inadequate.","descriptionTh":null,"extractedText":"Blackmores Iron Rapi-Melt All Products Shop All Products New Products Best Sellers Vegan Certified Women&#x27;s Health Men&#x27;s Health Kid&#x27;s Health Infant & Toddler Nutrition By Category Arthritis, Joint & Bone Brain & Cognitive Health Cold, Flu & Immunity Digestive & Gut Health Energy Everyday Health Eye Health Fish & Nutritional Oils Heart Health Infant & Toddler Nutrition Kids&#x27; Health Men&#x27;s Health Multivitamins Muscle Support Nails, Hair & Skin Preconception, Pregnancy & Breastfeeding Stress Relief & Sleep Support Women&#x27;s Health By Ingredient Calcium CoQ10 Curcumin Echinacea Fish Oil & Omega 3 Glucosamine Iron Magnesium Probiotics Selenium Vitamin B Vitamin C Vitamin D Vitamin E Zinc Health Hub By Categories By Type Latest Articles Action Plans Arthritis, Bone & Joint Beauty & Skincare Brain & Cognitive Health Cold, Flu & Immunity Digestive & Gut Health Energy Everyday Health Eye Health Fish & Nutrition Oils Heart & Cardiovascular Health Kids & Infant Health Men&#x27;s Health Muscle Support & Fitness Preconception, Pregnancy & Breastfeeding Recipes Stress Relief & Sleep Support Women&#x27;s Health Action Plans Articles Recipes Latest Articles About Blackmores About Blackmores Our Heritage Our Approach Our Impact Our Sustainability Pillars Our People & Culture Our Careers Our Ambassadors & Partners Contact us Ask A Naturopath Our Newsroom Blackmores Subscribe Search Home Chevron Icon Horizontal products Chevron Icon Horizontal Blackmores Iron Rapi-Melt™ Size Size 60 tablets 90 tablets Good health changes everything—support your iron needs with Blackmores Iron Rapi-Melt™. This innovative melt format delivers iron chelate and vitamin C in a fast-dissolving, tropical-flavoured tablet that’s ideal for people who have difficulty swallowing tablets. It helps relieve tiredness and fatigue when dietary intake is inadequate, while also supporting the absorption of dietary iron and maintaining iron levels in the body. Suitable for adolescents and pregnant or breastfeeding women, it also helps support general health and wellbeing, energy levels, and a healthy pregnancy when dietary intake is inadequate. Vitamin C enhances iron absorption and works synergistically with iron to help optimise uptake. With no artificial sweeteners or preservatives and 98% sugar-free, it’s a convenient and well-tolerated daily format that fits easily into your wellness routine. Product Format Orally disintegrating tablet (melt) Always read the label and follow the directions for use. Read the warnings before purchase. Support For Energy General Health No Added Yeast No Added Dairy No Added Soya Bean Benefits & How To Use Benefits Great tasting. Fast dissolving. Supports energy levels when dietary intake is inadequate. Relieves fatigue when dietary intake is inadequate. Supports general health and wellbeing. Supports absorption of dietary iron. Supports iron levels in the body. Supports healthy pregnancy when dietary intake is inadequate. With added vitamin C as a co-factor for absorption Dosage Adults, breastfeeding women and children 12 years and over Dissolve 1 melt (orally disintegrating tablet) in your mouth, two times a day. No water required. Pregnant women Dissolve 1 melt (orally disintegrating tablet) in your mouth, three times a day. No water required. Warnings Always read the label and follow the directions for use. Always talk to your health professional before taking multiple products for pregnancy. Advise your doctor of any medicine you take during pregnancy, particularly in your first trimester. Use in children only under adult supervision. Not recommended for children under 12 years. KEEP OUT OF REACH OF CHILDREN. Not for the treatment of iron deficiency conditions. If symptoms persist, talk to your health professional. Dietary supplements can only be of assistance if dietary intake is inadequate. If you have any pre-existing conditions or are on any medications always talk to your health professional before use. Some products should be ceased at least two weeks before any elective surgery, please confirm with your health professional. Contains sulfites. Benefits Dosage Warnings Great tasting. Fast dissolving. Supports energy levels when dietary intake is inadequate. Relieves fatigue when dietary intake is inadequate. Supports general health and wellbeing. Supports absorption of dietary iron. Supports iron levels in the body. Supports healthy pregnancy when dietary intake is inadequate. With added vitamin C as a co-factor for absorption Adults, breastfeeding women and children 12 years and over Dissolve 1 melt (orally disintegrating tablet) in your mouth, two times a day. No water required. Pregnant women Dissolve 1 melt (orally disintegrating tablet) in your mouth, three times a day. No water required. Always read the label and follow the directions for use. Always talk to your health professional before taking multiple products for pregnancy. Advise your doctor of any medicine you take during pregnancy, particularly in your first trimester. Use in children only under adult supervision. Not recommended for children under 12 years. KEEP OUT OF REACH OF CHILDREN. Not for the treatment of iron deficiency conditions. If symptoms persist, talk to your health professional. Dietary supplements can only be of assistance if dietary intake is inadequate. If you have any pre-existing conditions or are on any medications always talk to your health professional before use. Some products should be ceased at least two weeks before any elective surgery, please confirm with your health professional. Contains sulfites. The Blackmores Difference Ingredients Active ingredients per melt: Iron amino acid chelate 40 mg equivalent iron 8 mg Ascorbic acid (vitamin C) 30 mg Iron Rapi-Melt™ Reviews Let&#x27;s stay in touch Instagram Facebook TikTok LinkedIn Back To Top About Blackmores About Blackmores Our Heritage Our Approach Our Impact Our Sustainability Approach Our People & Culture Our Careers Our Ambassadors & Partners Our Newsroom Abo