  ('a2f3eacc-92a7-4ded-9cc4-8f33a695c2fc'::uuid, '8e1af7e2-feaf-43a8-898c-b348d5056744'::uuid, null, 'product_updated', 'admin_bulk_ignore_no_parseable_facts', '{"id":"8e1af7e2-feaf-43a8-898c-b348d5056744","title":"DHC Agaricus 30 Days","region":"TH","source":"manufacturer_import","status":"pending_review","brand_id":"17f6ebfb-bc28-4471-84e6-12fccfd93e06","category":null,"currency":"THB","platform":"manual","title_en":"DHC Agaricus 30 Days","title_th":"ดีเอชซี อะการิคัส 30 วัน","image_url":"https://www.dhc.co.jp/dw/image/v2/BLLL_PRD/on/demandware.static/-/Sites-dhc_catalog-ms/default/dwfa4ef902/large/32365/32365_G.png?sw=256&sh=256&sm=cut","brand_name":"dhc","created_at":"2026-05-21T10:14:11.157231+00:00","source_url":"https://www.dhc.co.jp/goods/32365.html","updated_at":"2026-05-22T00:30:35.729641+00:00","admin_notes":"Quality import validation kept this product pending review: No usable per-serving product facts.","description":"アガリクスの健康パワーが、負けない毎日をサポート","product_url":"https://www.dhc.co.jp/goods/32365.html","label_status":"missing","price_amount":null,"product_kind":"supplement","description_en":"Agaricus blazei mushroom powder supplement with yeast extract to support daily health and vitality.","description_th":"อาหารเสริมผงเห็ดอะการิคัส บลาเซอิ ผสมสารสกัดจากยีสต์ เพื่อสนับสนุนสุขภาพและความมีชีวิตชีวาในชีวิตประจำวัน","normalized_url":"https://www.dhc.co.jp/goods/32365.html","current_version":2,"fda_verified_at":null,"price_cached_at":null,"source_snapshot":{"locale":"ja","parser":"dhc_demandware_health_supplements_v1","titleEn":"DHC Agaricus 30 Days","titleTh":"ดีเอชซี อะการิคัส 30 วัน","htmlHash":"e1e7387d2c31b24e6efafa345e7682d0e91323f68473894885493a97c135d6e6","nutrition":"『アガリクス』は、健康維持に役立つβ-グルカンを含むアガリクス茸末に、同様のはたらきを持つとされる酵母抽出物をプラス！ いつまでも健康でいたい方、生活習慣が気になる方におすすめです。 アガリクスってなに？ アガリクスとは、実は、数百種類あるアガリクス属（ハラタケ属）のキノコの総称です。サラダやハヤシライスに入っているマッシュルームも実は、学名「アガリクス・ビスポラス」というアガリクス属のキノコなんです。 サプリメントに利用されるのは、学名「アガリクス・ブラゼイ・ムリル」で、和名では「ヒメマツタケ」と呼ばれます。 アガリクスのバリアパワーの源は、他のキノコにはない特殊なβ-グルカン！ 食事と健康の深い関係性に着目した“医食同源”の考え方のもと、キノコ類は古くより健康によい食材として用いられてきました。最近の研究では、キノコに含まれるβ-グルカンという多糖類がすこやかな毎日をバックアップすることがわかっています。「アガリクス・ブラゼイ・ムリル」には特に、他のキノコにない種類のβ-グルカンが含まれていることが知られています。 JANコード： 4511413618578 ※水またはぬるま湯で噛まずにそのままお召し上がりください。 ※本品は天然素材を使用しているため、色調に若干差が生じる場合があります。これは色の調整をしていないためであり、成分含有量や品質に問題はありません。 【名称】アガリクス茸加工食品 【原材料名】アガリクス茸末（国内製造）、酵母抽出物、乳糖、澱粉/セルロース、ステアリン酸Ca 【内容量】40.8g（1粒重量340mg×120粒） 【栄養成分表示［4粒1360mgあたり］】熱量5.0kcal、たんぱく質0.47g、脂質0.05g、炭水化物0.66g、食塩相当量0g、アガリクス茸末1280mg（β-グルカン8%）、酵母抽出物20mg アレルギー物質 乳 健康食品について ※一日摂取目安量を守って、お召し上がりください。 ※お身体に異常を感じた場合は、摂取を中止してください。 ※特定原材料及びそれに準ずるアレルギー物質を対象範囲として表示しています。原材料をご確認の上、食物アレルギーのある方はお召し上がりにならないでください。 ※薬を服用中あるいは通院中の方、妊娠中の方は、お医者様にご相談の上お召し上がりください。 ●直射日光、高温多湿な場所をさけて保存してください。 ●お子様の手の届かないところで保管してください。 ●開封後はしっかり開封口を閉め、なるべく早くお召し上がりください。 食生活は、主食、主菜、副菜を基本に、食事のバランスを。 レビュー 2025年以前のレビュー アガリクスは保険 2020年10月20日 田中勝 ｜ 愛用歴：10年0ヶ月 ｜ 愛知県 ｜ 63歳 アガリクスを飲むようになったのは、過去に父親が膀胱がんステージ4と診断され、ダメもとで、アガリクスの液体を購入して飲んでいたら、ステージ2までなったのを目の当たりにしたので、アガリクスは効くのではと思い、飲むようになりました。飲んでいる時は、効いているような。しかし、3ケ月やめていたら、体に異変があらわれた為、早々にアガリクスを注文して、飲んでいます。 関連する商品 キャンペーン 送料無料 【父の日限定】アスタキサンチン 30日分 3個セット 4,617 円 3,915 円（税込） 15%off 6月21日まで カートに入れる キャンペーン ネコポス コンビニ受取 亜鉛 30日分 3個セット 810 円 783 円（税込） 3%off 6月2日まで カートに入れる キャンペーン 送料無料 ネコポス コンビニ受取 醗酵黒セサミン プレミアム 30日分 2個セット 5,940 円 5,697 円（税込） 4%off 6月25日まで カートに入れる キャンペーン 送料無料 【父の日限定】香酢（こうず） 30日分 4個セット 4,752 円 3,888 円（税込） 18%off 6月21日まで カートに入れる 関連カテゴリ 健康食品・サプリメント 健康食品・サプリメント 目的で探す 元気・スタミナ カートに追加しました この商品はすでにお気に入りリストに追加されています。 新作アイテム今すぐチェック --> 新作アイテム 今すぐチェック 新作アイテム今すぐチェック --> お買い得商品を お見逃しなく！ 新作アイテム今すぐチェック --> 最大25％OFF 業界最大級の割引率 新作アイテム今すぐチェック --> オンラインショップ 限定品 新作アイテム今すぐチェック --> 安全性を第一に考えた 製品づくり 新作アイテム今すぐチェック --> 読み物や特集ページは コチラ お得な購入特典 すべて見る 最大10%OFF！ 一括購入割引 税込3,780円以上のご購","productId":"32365","validation":{"status":"failed","reasons":["no_canonical_match","no_dosed_facts"],"summary":"No usable per-serving product facts.","checkedAt":"2026-05-22T00:30:35.728Z","matchableFactCount":0},"description":"アガリクスの健康パワーが、負けない毎日をサポート","importScope":"dhc_japan_supplemen