  ('b370319a-ee90-48f2-a1d1-222bf60c0977'::uuid, '1dc89b72-d8e7-4e6e-8c99-6c2b6ed266ca'::uuid, null, 'product_updated', 'codex_blackmores_clean_approval', '{"id":"1dc89b72-d8e7-4e6e-8c99-6c2b6ed266ca","title":"Blackmores Energy B12 Rapi-Melt™","region":"TH","source":"manufacturer_import","status":"pending_review","brand_id":"40e4806a-5049-4668-8d29-ab36a31202dd","category":null,"currency":"THB","platform":"manual","title_en":"Blackmores Energy B12 Rapi-Melt™","title_th":null,"image_url":"https://images.contentstack.io/v3/assets/blt948bd74310fc0ad0/blt76c5191de6dcb203/68bfb4c87d7baa3093887527/9300807364413-1.webp","brand_name":"blackmores","created_at":"2026-05-21T13:09:45.217599+00:00","source_url":"https://www.blackmores.com.au/products/energy-b12-rapi-melt","updated_at":"2026-05-21T13:09:45.231902+00:00","admin_notes":null,"description":"Blackmores Energy B12 Rapi-Melt™ supports energy levels and nervous system function.","product_url":"https://www.blackmores.com.au/products/energy-b12-rapi-melt","label_status":"parsed","price_amount":null,"product_kind":"supplement","description_en":"Blackmores Energy B12 Rapi-Melt™ supports energy levels and nervous system function.","description_th":null,"normalized_url":"https://www.blackmores.com.au/products/energy-b12-rapi-melt","current_version":1,"fda_verified_at":null,"price_cached_at":null,"source_snapshot":{"dosage":"for use. Read the","locale":"en","parser":"blackmores_structured_ingredients_v2","titleEn":"Blackmores Energy B12 Rapi-Melt™","htmlLength":169249,"validation":{"status":"pass","reasons":[],"summary":"1 matchable canonical fact.","checkedAt":"2026-05-21T13:09:45.228Z","matchableFactCount":1},"description":"Blackmores Energy B12 Rapi-Melt™ supports energy levels and nervous system function.","descriptionEn":"Blackmores Energy B12 Rapi-Melt™ supports energy levels and nervous system function.","descriptionTh":null,"extractedText":"Blackmores Energy B12 Rapi-Melt All Products Shop All Products New Products Best Sellers Vegan Certified Women&#x27;s Health Men&#x27;s Health Kid&#x27;s Health Infant & Toddler Nutrition By Category Arthritis, Joint & Bone Brain & Cognitive Health Cold, Flu & Immunity Digestive & Gut Health Energy Everyday Health Eye Health Fish & Nutritional Oils Heart Health Infant & Toddler Nutrition Kids&#x27; Health Men&#x27;s Health Multivitamins Muscle Support Nails, Hair & Skin Preconception, Pregnancy & Breastfeeding Stress Relief & Sleep Support Women&#x27;s Health By Ingredient Calcium CoQ10 Curcumin Echinacea Fish Oil & Omega 3 Glucosamine Iron Magnesium Probiotics Selenium Vitamin B Vitamin C Vitamin D Vitamin E Zinc Health Hub By Categories By Type Latest Articles Action Plans Arthritis, Bone & Joint Beauty & Skincare Brain & Cognitive Health Cold, Flu & Immunity Digestive & Gut Health Energy Everyday Health Eye Health Fish & Nutrition Oils Heart & Cardiovascular Health Kids & Infant Health Men&#x27;s Health Muscle Support & Fitness Preconception, Pregnancy & Breastfeeding Recipes Stress Relief & Sleep Support Women&#x27;s Health Action Plans Articles Recipes Latest Articles About Blackmores About Blackmores Our Heritage Our Approach Our Impact Our Sustainability Pillars Our People & Culture Our Careers Our Ambassadors & Partners Contact us Ask A Naturopath Our Newsroom Blackmores Subscribe Search Home Chevron Icon Horizontal products Chevron Icon Horizontal Blackmores Energy B12 Rapi-Melt™ Size Size 60 tablets 90 tablets Good health changes everything—support your energy needs with Blackmores Energy B12 Rapi-Melt. This convenient orally disintegrating tablet delivers 1000 micrograms of vitamin B12 as mecobalamin, an active form of B12. It helps maintain energy levels, support energy production, and assist healthy red blood cell production. It also supports nervous system function and general health and wellbeing. Blackmores Rapi-Melts are orally disintegrating tablets that are great for those who have trouble swallowing conventional tablets. They dissolve on the tongue in under three minutes and provide an easy-to-swallow format with no water required. This format is suitable for vegans and vegetarians and is 98% sugar free with no artificial sweeteners or preservatives. Taken once daily, Blackmores Energy B12 Rapi-Melt provides targeted nutritional support for individuals with increased energy demands or those needing support when dietary intake of B12 is inadequate. Product Format Orally disintegrating tablet (melt) Always read the label and follow the directions for use. Read the warnings before purchase. Support For Energy General Health Nervous System Health Fatigue Halal Certified No Added Yeast No Added Soya Bean No Added Dairy Vegan Certified Benefits & How To Use Benefits Supports energy levels. Supports energy production. Relieves tiredness. Supports general health and wellbeing. Aids healthy red blood cell production. Supports B12 within normal range. Supports cognitive function when dietary intake is inadequate. Supports nervous system function. Dosage Adults Dissolve 1 melt (orally disintegrating tablet) in your mouth, once a day. No water required. Warnings Always read the label and follow the directions for use. Do not use during pregnancy or breastfeeding. Dietary supplements can only be of assistance if dietary intake is inadequate. If symptoms persist, talk to your health professional. If you have any pre-existing conditions or are on any medications, always talk to your health professional before use. Some products should be ceased at least two weeks before any elective surgery, please confirm with your health professional. Contains sulfites. Benefits Dosage Warnings Supports energy levels. Supports energy production. Relieves tiredness. Supports general health and wellbeing. Aids healthy red blood cell production. Supports B12 within normal range. Supports cognitive function when dietary intake is inadequate. Supports nervous system function. Adults Dissolve 1 melt (orally disintegrating tablet) in your mouth, once a day. No water required. Always read the label and follow the directions for use. Do not use during pregnancy or breastfeeding. Dietary supplements can only be of assistance if dietary intake is inadequate. If symptoms persist, talk to your health professional. If you have any pre-existing conditions or are on any medications, always talk to your health professional before use. Some products should be ceased at least two weeks before any elective surgery, please confirm with your health professional. Contains sulfites. The Blackmores Difference Ingredients Active ingredients per melt: Mecobalamin (vitamin B12) 1000 micrograms (1 mg) Energy B12 Rapi-Melt™ Reviews Let&#x27;s stay in touch Instagram Facebook TikTok LinkedIn Back To Top About Blackmores About Blackmores Our Heritage Our Approach Our Impact Our Sustainability Approach Our People & Culture Our Careers Our Ambassadors & Partners Our Newsroom About Blackmores About Blackmores Our Heritage Our Approach Our Impact Our Sustainability Approach Our People & Culture Our Careers Our Ambassadors & Partners Our Newsroom Our Brands & Products Shop Our Products Shop Best Sellers BioCeuticals Blackmores Professional Blackmores Institute Blackmores Education Our Brands & Products Shop Our Products Shop Best Sellers BioCeuticals Blackmores Professional Blackmores Institute Blackmores Education International Markets China Hong Kong SAR iHerb Indonesia Korea Malaysia New Zealand Singapore Taiwan Region Thailand Vietnam International Markets China Hong Kong SAR iHerb Indonesia Korea Malaysia New Zealand Singapore Taiwan Region Thailand Vietnam Terms & Policies Privacy Policy & Practices Terms Of Purchase Terms of Service Posting Guidelines Social Media House Rules Terms & Policies Privacy Policy & Practices Terms Of Purchase Terms of Service Posting Guidelines Social Media House Rules Contacts & FAQs Report a Suspected Adverse Experience Contact Us Ask a Naturopath Product & Purchasing FAQs Blackmores Subscribe Contacts & FAQs Report a Suspected Adverse Experience Contact Us Ask a Naturopath Product & Purchasing FAQs Blackmores Subscribe Back To Top Terms of Purchase Privacy Policy ©2025 Blackmores. All Rights Reserved. ©2025 Blackmores. All Rights Reserved.","productImportId":"5c1c0939-5800-4f5a-88a7-eadda01eacce","aiFactCorrection":{"notes":"Standardized mecobalamin to canonical Vitamin B12; dose confirmed from structured ingredients table","responseId":"4987646b-3f17-9339-9c14-f2ecb3da8904","correctedAt":"2026-05-18T16:45:04.303Z","originalFactCount":1,"correctedFactCount":1},"activeIngredientCount":1,"structuredIngredients":[{"uid":"cs8030141c2a39f46d","type":"Title","units":null,"amount":null,"ingredientName":"Active ingredients per melt:"},{"uid":"cse98d34787ea88c53","type":"Main","units":"micrograms (1 mg)","amount":1000,"ingredientName":"Mecobalamin (vitamin B12)"}],"candidateSupplierReason":"Blackmores Thailand product pages expose structured active ingredient tables, product images and FDA advertising approval text."},"affiliate_status":"none","normalized_title":"blackmores_energy_b12_rapi_melt","product_audience":"both","validation_status":"pass","validation_reasons":[],"validation_summary":"1 matchable canonical fact.","availability_status":"unknown","external_product_id":null,"fda_approval_number":null,"affiliate_checked_at":null,"normalized_brand_name":"blackmores","validation_checked_at":"2026-05-21T13:09:45.228+00:00","availability_cached_at":null,"product_data_expires_at":null}'::jsonb, '{"status":"approved","version":2,"changeNote":"approve_clean_blackmores_validation_pass","validation":{"status":"pass","reasons":[],"summary":"1 matchable canonical fact.","checkedAt":"2026-05-21T13:10:32.555Z","matchableFactCount":1},"sourceSnapshotPatch":null,"manufacturerCountriesChanged":false}'::jsonb, '2026-05-21T13:10:32.558Z'::timestamptz),
